function addBusinessDays(date: Date, days: number): Date {
  const result = new Date(date);
  let added = 0;
  while (added < days) {
    result.setDate(result.getDate() + 1);
    const dow = result.getDay();
    if (dow !== 0 && dow !== 6) added++;
  }
  return result;
}

export function computeDeadline(newStatus: string, from: Date): string | null {
  if (newStatus.startsWith("S1 ") || newStatus === "S1 - New Lead") {
    return addBusinessDays(from, 2).toISOString().slice(0, 10);
  }
  if (newStatus.startsWith("S2 ")) {
    return addBusinessDays(from, 5).toISOString().slice(0, 10);
  }
  if (newStatus.startsWith("S7 ")) {
    return addBusinessDays(from, 5).toISOString().slice(0, 10);
  }
  return null;
}

